-- grid_module.lua
-- Grid firmware entry point for the compiled-song player (lite stack).
--
-- This is the MINIMAL on-device player: a precompiled song table walked
-- by a tiny pulse-clock player.  No sequencer engine on device.
--
-- ── Files to upload to the Grid module ────────────────────────────────────
-- Each library lives in its own folder so it can be uploaded / removed
-- independently.  Generated by:
--   lua tools/gridsplit.lua  --require-prefix /player       \
--                            --outdir grid/player           \
--                            player_lite/player.lua
--   lua tools/song_compile.lua --require-prefix /dark_groove \
--                              --outdir grid/dark_groove     \
--                              songs/dark_groove.lua
--
-- Then upload:
--   grid/player/*.lua       → /player/  on the Grid module
--   grid/dark_groove/*.lua  → /dark_groove/  on the Grid module
--
-- ── Firmware API assumed ──────────────────────────────────────────────────
--   midi_send(channel, status_byte, note, velocity)
--   element_timer_start(element_index, delay_ms)
--   self:element_index()
--
-- ── Clock source ──────────────────────────────────────────────────────────
-- Grid firmware does not expose uv.now().  We maintain SEQ_CLOCK_MS,
-- a simple integer that increments by the timer interval on every tick.
--
-- ── Require paths ─────────────────────────────────────────────────────────
-- Grid's require() resolves the module name as a literal file path; the
-- standard package.path "?" substitution does NOT work.  Therefore every
-- require uses the full path including the leading slash, e.g.
-- require("/player/seq_player").  The splitter and song compiler bake
-- these paths in via --require-prefix so chunks self-load correctly.

-- ═══════════════════════════════════════════════════════════════════════════
-- INIT BLOCK  (paste into element 0 init event — runs once on config load)
-- ═══════════════════════════════════════════════════════════════════════════

local Player = require("/player/seq_player")
local song   = require("/dark_groove/dark_groove")

-- Software ms counter — incremented each tick by SEQ_INTERVAL.
SEQ_CLOCK_MS = 0
local function gridClockFn() return SEQ_CLOCK_MS end

SEQ_PLAYER   = Player.new(song, gridClockFn)
-- Tick interval: the player walks the song against pulses, so we choose a
-- timer rate fine enough to resolve the smallest gate.  Half the pulse
-- interval is plenty.  At BPM 118, ppb 4 → pulse ≈ 127ms → tick ≈ 60ms.
SEQ_INTERVAL = math.floor(SEQ_PLAYER.pulseMs / 2)

-- MIDI emit: route player events to firmware MIDI API.
-- Lite player passes (eventType, pitch, velocity, channel) directly.
function SEQ_EMIT(eventType, pitch, velocity, channel)
    if eventType == "NOTE_ON" then
        midi_send(channel, 0x90, pitch, velocity)
    else
        midi_send(channel, 0x80, pitch, 0)
    end
end

Player.start(SEQ_PLAYER)
element_timer_start(0, SEQ_INTERVAL)

-- ═══════════════════════════════════════════════════════════════════════════
-- TIMER BLOCK  (paste into element 0 timer event — self-restarting loop)
-- ═══════════════════════════════════════════════════════════════════════════

local Player = require("/player/seq_player")

SEQ_CLOCK_MS = SEQ_CLOCK_MS + SEQ_INTERVAL
Player.tick(SEQ_PLAYER, SEQ_EMIT)
element_timer_start(self:element_index(), SEQ_INTERVAL)

